UPDATE Language_RU_RU
SET Text = 'Всемирный конгресс возрождается как Объединенные Нации. Созывается специальная сессия для выбора хозяина этой мощной новой дипломатической силы. Объединенные Нации продолжат работу как и раньше, но регулярные сессии будут чередоваться с сессиями, позволяющими цивилизациям попытаться заявить о глобальной гегемонии, делая [COLOR_POSITIVE_TEXT]дипломатическую победу[ENDCOLOR] возможной. Чтобы включить эти сессии, должна действовать [COLOR_POSITIVE_TEXT]резолюция о мировой идеологии[ENDCOLOR].'
WHERE Tag = 'TXT_KEY_LEAGUE_SPECIAL_SESSION_START_UNITED_NATIONS_HELP';
